import{c as t,Q as a,j as n,m as o}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Turing Post — 2026-04-21","description":"","frontmatter":{"title":"Turing Post — 2026-04-21","date":"2026-04-21T00:00:00.000Z","source":"Turing Post","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-21-turing-post.md","filePath":"research/ai-news/2026-04/2026-04-21-turing-post.md","lastUpdated":1779894392000}'),r={name:"research/ai-news/2026-04/2026-04-21-turing-post.md"};function i(s,e,l,h,p,d){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="🏛️-turing-post-—-2026-04-21" tabindex="-1">🏛️ Turing Post — 2026-04-21 <a class="header-anchor" href="#🏛️-turing-post-—-2026-04-21" aria-label="Permalink to &quot;🏛️ Turing Post — 2026-04-21&quot;">​</a></h1><blockquote><p>Ksenia Se 主持，95k+ 訂閱；AI/ML 政策、地緣政治與深度洞察 來源：<a href="https://turingpost.substack.com/feed" target="_blank" rel="noreferrer">Turing Post</a></p></blockquote><hr><h2 id="fod-149-why-palantir-s-manifesto-went-viral-without-saying-anything-new" tabindex="-1"><a href="https://turingpost.substack.com/p/fod149-why-palantirs-manifesto-went" target="_blank" rel="noreferrer">FOD#149: Why Palantir’s Manifesto Went Viral Without Saying Anything New</a> <a class="header-anchor" href="#fod-149-why-palantir-s-manifesto-went-viral-without-saying-anything-new" aria-label="Permalink to &quot;[FOD#149: Why Palantir’s Manifesto Went Viral Without Saying Anything New](https://turingpost.substack.com/p/fod149-why-palantirs-manifesto-went)&quot;">​</a></h2><p><em>🏛️ Turing Post | 2026-04-21</em></p><p>This Week in Turing Post:</p><p>Wednesday / AI 101 series: What token are we talking about? Token Taxonomy</p><p>Friday / The Org Age of AI: What real AI adoption looks like in an established company or enterprise</p><p>To the main topic →</p><p>Suddenly, everyone is buzzing about a 22-point manifesto published by Palantir. Their post on X crossed all corporate expectations and, at the moment of writing, it has over 25 million views.</p><p>Their previous posts, even controversial ones, rarely moved beyond ~100k. More to that, this manifesto has nothing new in it: it is a compressed version of The Technological Republic, co-authored by Alex Karp and Nicholas W. Zamiska and published at the beginning of 2025. Yes, more than a year ago. The core ideas are: a shift from soft power to hard capabilities, tighter alignment between tech and government, and a renewed focus on national purpose in a technological age. Same old, same old for Palantir.</p><p>So why did this particular post – with nothing new in it – travel so far?</p><p>Part of it is distribution. X has become a very different system. Whatever Elon Musk changed, content now travels faster, farther, and with less friction. A long-form argument becomes a short, structured object that can be screenshotted, quoted, attacked, and redistributed across tightly connected networks of policymakers, investors, engineers, and media. The format also works great. A numbered, declarative thread is engineered for this platform, where strong positions travel further than careful ones.</p><p>You see how it spreads like a forest fire. And with the war in Iran, that forest was already dry. The US is not talking about AI in abstract terms anymore. Systems like Palantir’s Maven are already embedded in military operations, analyzing sensor data and supporting targeting decisions. When Palantir writes “AI weapons will be built” it sounds almost coy: AI weapons are already built, and Palantir is one of them actively selling them.</p><p>But they not only building and selling them. Palantir’s role has shifted.</p><p>It is no longer simply a vendor selling software into government contracts. It is becoming embedded in systems that are difficult to replace once deployed. Its tools are used in operational environments where data from multiple sources is combined into decisions with real consequences. This changes the nature of the conversation around the company.</p><p>Once you reach that position, neutrality is not an option. Through this manifesto they achieve a few things:</p><p>Filtering customers. Some will prefer a partner that is explicit about its priorities. Others will not.</p><p>Filtering talent. Some engineers are increasingly disillusioned with consumer technology and are drawn to systems that operate at the level of national infrastructure. Others are not.</p><p>Filtering partners and investors. Clarity reduces ambiguity, even when it increases controversy.</p><p>And, of course, showing the finger to everyone who disagrees.</p><p>And they want to fully own it. This is where the move becomes strategically important.</p><p>Palantir is the first major AI company to treat ideology as a competitive moat. As part of how it competes. If a company is selling into national security systems, alignment becomes part of the product. That alignment is not easily reproduced by competitors whose business models depend on broader, more neutral positioning.</p><p>The traditional sources of advantage in AI are becoming less distinct. Model performance is converging. Infrastructure is more widely accessible. Distribution remains important, but it is no longer exclusive. In that environment, political and institutional alignment becomes a differentiator.</p><p>What Palantir is building is a form of irreplaceability that does not depend only on technical capability. Now they have 22 points about it that went viral.</p><p>Notice what happened after the post went up. Anthropic said nothing. OpenAI said nothing. Google DeepMind said nothing. xAI said nothing. Microsoft said nothing. This may mean, as we’d like to argue, that every AI company with a defense-adjacent business watched Palantir plant this flag and chose not to react because silence is the only response that does not lose. It may also mean, more prosaically, that large companies rarely respond to competitors’ press events. The evidence currently fits both readings. Worth watching over the next six months whether these companies shift their behavior – defense pitches, recruiting language, procurement strategies – rather than just their statements.</p><p>That raises a broader question for the industry. What happens once this category exists?</p><p>Three paths are possible. Gradual convergence, where other labs move in a similar direction but in moderated form, adopting language around national alignment without fully committing to it. Bifurcation, where the industry separates into companies aligned with defense and government systems and those focused on commercial and consumer applications. Arbitrage, where some companies attempt to operate across both domains, maintaining a neutral public position while participating in government deployments. Anthropic and OpenAI are structurally positioned to attempt this.</p><p>In my opinion, most AI labs will adopt softened versions of Palantir’s posture – “American AI,” “democracy-aligned AI,” “frontier defense” – that capture part of the signal at a fraction of the reputational cost. The real split may happen along geographic lines rather than corporate ones. European and Asian AI ecosystems are likely to define themselves partly in opposition to the American defense-aligned pole, and foreign governments will hedge by building domestic alternatives rather than forcing vendors into binary commitments.</p><p>The underlying shift is more consistent than any single scenario. AI is moving from a tool layer into infrastructure. Infrastructure carries alignment, whether it is stated explicitly or not.</p><p>Palantir is earlier than most in stating it directly – and choosing the perfect way to ride the new X algorithms.</p><p>→ If any of those thoughts resonate with you – share them across your social networks. Let’s keep the conversation going.</p><p>Topic 2: The episode in which Dwarkesh Patel got Jensen Huang to call Dario Amodei’s mindset a mindset of a loser! Why did Jensen get genuinely angry in this conversation? There is much more depth to it than you think. <a href="https://www.youtube.com/watch?v=z_be7EOkBRo" target="_blank" rel="noreferrer">Let’s discuss </a><a href="https://www.youtube.com/watch?v=z_be7EOkBRo" target="_blank" rel="noreferrer">→</a></p><p>Follow us on 🎥<a href="https://www.youtube.com/@RealTuringPost" target="_blank" rel="noreferrer"> YouTube</a> <a href="https://x.com/TheTuringPost" target="_blank" rel="noreferrer">Twitter</a> <a href="https://huggingface.co/Kseniase" target="_blank" rel="noreferrer"> Hugging Face </a>🤗</p><p>Twitter Library</p><p><a href="https://www.turingpost.com/p/attention-types" target="_blank" rel="noreferrer">13+ Attention Mechanisms You Should Know</a></p><p>We are reading/watching/learning:</p><p><a href="https://www.youtube.com/watch?v=oNJtSBtqXrY" target="_blank" rel="noreferrer">“Intention is what we need”: Neeru Khosla on the Future of Education and Learning with AI</a></p><p><a href="https://blog.eladgil.com/p/random-thoughts-while-gazing-at-the" target="_blank" rel="noreferrer">Random thoughts while gazing at the misty AI Frontier</a> by Elad Gil</p><p><a href="https://www.interconnects.ai/p/my-bets-on-open-models-mid-2026" target="_blank" rel="noreferrer">My bets on open models, mid-2026</a> by Nathan Lambert</p><p><a href="https://x.com/deedydas/status/2045684751529603525" target="_blank" rel="noreferrer">Every single book that influenced Demis Hassabis and DeepMind (and how it inspired them), from “Infinity Machine”</a> put together by Deedy</p><p><a href="https://x.com/jaynitx/status/2045486658938888598" target="_blank" rel="noreferrer">The neuroscience of visualization: why it works (but not how you think) </a>by Jaynit</p><p><a href="https://x.com/raw_works/status/2046240194999755153" target="_blank" rel="noreferrer">RLMs are the new reasoning models</a> by Raymond Weitekamp</p><p>News from the usual suspects ™ (rivals rivals rivals)</p><p>Anthropic</p><p>Capability, With a Lock on the Door Claude Opus 4.7 <a href="https://www.anthropic.com/news/claude-opus-4-7" target="_blank" rel="noreferrer">ships</a> publicly, while Mythos stays restricted due to cyber-offensive potential. The gap is now explicit: the best systems are not automatically released. Access is negotiated, staged, and in some cases withheld entirely.</p><p>Talking to Governments (Because They Have To) <a href="https://www.bbc.com/news/articles/cyv10e1d13po" target="_blank" rel="noreferrer">Ongoing</a> conversations with U.S. officials around security implications signal a shift from product rollout to geopolitical coordination. Frontier models are now treated as infrastructure with risk profiles, not just features.</p><p>Anthropic’s Automated Alignment Researchers are <a href="https://alignment.anthropic.com/2026/automated-w2s-researcher/" target="_blank" rel="noreferrer">running</a> parallel, end-to-end research cycles, turning months of human effort into days of compute. On one benchmark, they leapt from a human-tuned score of 0.23 to 0.97, a rather impolite gap. The catch: they also learned to game evaluations in surprisingly creative ways. Progress, it seems, now comes with its own internal audit problem.</p><p>OpenAI</p><p>Going Vertical, For Real Two focused releases: <a href="https://openai.com/index/introducing-gpt-rosalind/" target="_blank" rel="noreferrer">GPT-Rosalind</a> for life sciences and <a href="https://openai.com/index/scaling-trusted-access-for-cyber-defense/" target="_blank" rel="noreferrer">GPT-5.4-Cyber</a> for security workflows. This is a clean move away from “one model for everything” toward domain-specific systems embedded in high-stakes environments.</p><p>Codex Wants the Whole Desk Now Codex is no longer content with writing code – it is <a href="https://openai.com/index/codex-for-almost-everything/" target="_blank" rel="noreferrer">angling</a> to run the whole workflow. With computer control, memory, plugins, and long-running task automation, it is becoming less a tool and more a colleague who never logs off. Now further strengthened by the <a href="https://www.wired.com/story/openai-executive-kevin-weil-is-leaving-the-company/" target="_blank" rel="noreferrer">folding </a>of the ambitious Prism science workspace into Codex</p><p>Google – Running Both Ends of the Stack On one side: talks to <a href="https://www.tomshardware.com/tech-industry/artificial-intelligence/google-and-pentagon-in-talks-to-run-tpus-inside-classified-environments" target="_blank" rel="noreferrer">deploy</a> Gemini and TPUs in classified environments, with explicit constraints around sensitive use cases. On the other: expanding AI across consumer surfaces – Android, Chrome, XR. Underneath, continued investment in custom silicon and new chip partnerships. Google is trying to be both ubiquitous and trusted, which is harder than it sounds.</p><p>🔦 Paper Highlight</p><p>Dive into Claude Code: The design space of today’s and future AI agent systems</p><p>What’s fascinating is how little of Claude Code is actually “intelligence.” Researchers from Mohamed bin Zayed University of Artificial Intelligence found a tiny reasoning core wrapped in massive infrastructure: ~512K lines, 1,884 files, seven permission modes, 54 tools, 27 hooks, five context-compression layers, isolated subagents, and append-only transcripts. The real innovation is the harness: safety, memory, delegation, and recovery – not just the LLM <a href="https://arxiv.org/pdf/2604.14228" target="_blank" rel="noreferrer">→read their study</a></p><p>Models</p><p>HY-World 2.0: A Multi-Modal World Model for Reconstructing, Generating, and Simulating 3D Worlds Builds a multimodal world model that turns text, images, and video into navigable 3D environments <a href="https://arxiv.org/abs/2604.14268" target="_blank" rel="noreferrer">→read the paper</a></p><p>Kimi K2.6 goes under Model Tech Reports or Coding / Agentic Models. Moonshot’s official blog frames it as an open-source coding model with long-horizon execution, 4,000+ tool calls, 12+ hours of continuous execution, stronger agent swarms, and production use through Kimi Code and API access <a href="https://x.com/Kimi_Moonshot/status/2046249571882500354" target="_blank" rel="noreferrer">→check their tweet</a></p><p>Nvidia:</p><p>Isaac GR00T N1.7 also goes under Models, but specifically Embodied / Physical AI Models or Robotics Foundation Models. NVIDIA describes it as an open, commercially licensed vision-language-action model for humanoids, with dexterous control and training grounded in large-scale egocentric human video <a href="https://huggingface.co/blog/nvidia/gr00t-n1-7" target="_blank" rel="noreferrer">→check at Hugging Face</a></p><p>Nemotron 3 Super: Open, Efficient Mixture-of-Experts Hybrid Mamba-Transformer Model for Agentic Reasoning Presents an open hybrid MoE reasoning model optimized for long context, throughput, and efficient inference <a href="https://arxiv.org/abs/2604.12374" target="_blank" rel="noreferrer">→read the paper </a></p><p>Audio Flamingo Next Advances audio-language modeling with stronger reasoning, longer audio context, and timestamp-grounded temporal chain-of-thought <a href="https://arxiv.org/abs/2604.10905" target="_blank" rel="noreferrer">→read the paper </a></p><p>Lyra 2.0: Explorable Generative 3D Worlds Generates persistent explorable 3D worlds by combining long-horizon video generation with feed-forward 3D reconstruction <a href="https://arxiv.org/abs/2604.13036" target="_blank" rel="noreferrer">→read the paper </a></p><p>Qwen3.5-Omni Technical Report Introduces a large omni-modal model for text, vision, audio, speech, and structured audio-visual interaction <a href="https://arxiv.org/abs/2604.15804" target="_blank" rel="noreferrer">→read the paper </a></p><p>Research</p><p>Trends we see:</p><p>how to create better learning signal</p><p>how to sustain longer agentic workflows</p><p>how to make generation or reasoning more adaptive instead of uniformly expensive.</p><hr>',70)])])}const u=t(r,[["render",i]]);export{g as __pageData,u as default};
